function isPerfect(n) {
  if (n <= 1) return false;
  let sum = 1; // 1 is always divisor
  for (let i = 2; i * i <= n; i++) {
    if (n % i === 0) {
      sum += i;
      if (i !== n / i) sum += n / i;
    }
  }
  return sum === n;
}

function isPerfectFilter(n) {
  return Array.from({ length: Math.floor(Math.sqrt(n)) }, (_, i) => i + 2)
    .filter(i => n % i === 0)
    .reduce((sum, i) => sum + i + (i !== n/i ? n/i : 0), 1) === n;
}
